#include <stdio.h>
#include <stdlib.h>
int compare(const void *a, const void *b) {
    int *x = (int *)a;
    int *y = (int *)b;
    return x[1] - y[1];
}
int main() {
    int n;
    scanf("%d", &n);
    int activities[n][2];
    for (int i = 0; i < n; i++) {
        scanf("%d %d", &activities[i][0], &activities[i][1]);
    }
    qsort(activities, n, sizeof(activities[0]), compare);
    int count = 1;
    int last_end = activities[0][1];
    for (int i = 1; i < n; i++) {
        if (activities[i][0] >= last_end) {
            count++;
            last_end = activities[i][1];
        }
    }
    printf("%d\n", count);
    return 0;
}

